export default function PolyphonicSynchronicity() {
  const [page, setPage] = useState("home");
  const [selectedBook, setSelectedBook] = useState(null);
  const [activeQuarter, setActiveQuarter] = useState("June");

  const styles = {
    global: {
      fontFamily: FONTS.sans,
      background: COLORS.parchment,
      color: COLORS.ink,
      minHeight: "100vh",
    },
    nav: {
      position: "sticky",
      top: 0,
      zIndex: 100,
      background: "rgba(250,247,242,0.97)",
      borderBottom: `1px solid ${COLORS.border}`,
      display: "flex",
      alignItems: "center",
      justifyContent: "space-between",
      padding: "1rem 2.5rem",
      backdropFilter: "blur(8px)",
    },
    navLogo: {
      fontFamily: FONTS.serif,
      fontSize: "1rem",
      fontWeight: 700,
      color: COLORS.ink,
      letterSpacing: "0.02em",
      cursor: "pointer",
      fontStyle: "italic",
    },
    navLinks: {
      display: "flex",
      gap: "2rem",
      listStyle: "none",
      margin: 0,
      padding: 0,
    },
  };

  const navLinkStyle = (active) => ({
    fontFamily: FONTS.sans,
    fontSize: "0.78rem",
    fontWeight: 400,
    color: active ? COLORS.goldDark : COLORS.muted,
    cursor: "pointer",
    letterSpacing: "0.1em",
    textTransform: "uppercase",
    borderBottom: active ? `1px solid ${COLORS.gold}` : "1px solid transparent",
    paddingBottom: "2px",
    transition: "color 0.2s",
  });

  const navigate = (p) => { setPage(p); window.scrollTo(0, 0); };

  if (page === "bookdetail" && selectedBook) {
    return <BookDetail book={selectedBook} onBack={() => navigate("home")} />;
  }

  return (
    <div style={styles.global}>
      <style>{googleFonts}</style>
      <nav style={styles.nav}>
        <span style={styles.navLogo} onClick={() => navigate("home")}>
          Polyphonic Synchronicity
        </span>
        <ul style={styles.navLinks}>
          {[
            { label: "June Reads", id: "home" },
            { label: "Reading List", id: "readinglist" },
            { label: "S&S Book Club", id: "bookclub" },
          ].map(({ label, id }) => (
            <li key={id}>
              <span style={navLinkStyle(page === id)} onClick={() => navigate(id)}>{label}</span>
            </li>
          ))}
        </ul>
      </nav>

      {page === "home" && (
        <HomePage
          books={JUNE_BOOKS}
          onBookClick={(book) => { setSelectedBook(book); navigate("bookdetail"); }}
        />
      )}
      {page === "readinglist" && (
        <ReadingListPage
          list={READING_LIST}
          activeQuarter={activeQuarter}
          setActiveQuarter={setActiveQuarter}
          categories={QUARTERLY_CATEGORIES}
        />
      )}
      {page === "bookclub" && <BookClubPage data={SANDEEP_SHOBA} />}
    </div>
  );
}

